// TypeScript implementation for Generic Functions
interface GenericFunctionsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processGenericFunctions(item: GenericFunctionsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processGenericFunctions({ id: 1, title: 'Generic Functions', status: 'active' }));

